local function set_hl(groups, value)
	for _, v in pairs(groups) do
		vim.api.nvim_set_hl(0, v, value)
	end
end

set_hl({
	"MiniFilesBorder",
	"MiniFilesNormal",
	"MiniFilesTitle",
	"MiniPickBorder",
	"MiniPickBorderBusy",
	"MiniPickBorderText",
	"MiniPickHeader",
